'use client'

import { useEffect, useState } from 'react'
import { FileText, Loader2, ArrowLeft, RefreshCw, Trash2, X } from 'lucide-react'
import Link from 'next/link'
import jsPDF from 'jspdf'
import autoTable from 'jspdf-autotable'

interface WarehouseItem {
  id: string
  name: string
  patrimony: string | null
  unit: string
  imageUrl: string
  status: string
  createdAt: string
}

export default function DashboardInventario() {
  const [items, setItems] = useState<WarehouseItem[]>([])
  const [loading, setLoading] = useState(true)
  const [pdfLoading, setPdfLoading] = useState(false)
  const [zoomedImage, setZoomedImage] = useState<string | null>(null)

  const fetchItems = async () => {
    setLoading(true)
    try {
      const res = await fetch('/api/inventario')
      if (res.ok) {
        const data = await res.json()
        setItems(data)
      }
    } catch (error) {
      console.error(error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchItems()
  }, [])

  const handleDelete = async (id: string) => {
    const confirmDelete = window.confirm("Tem certeza que deseja apagar este item? Essa ação não pode ser desfeita.")
    if (!confirmDelete) return

    try {
      const res = await fetch(`/api/inventario?id=${id}`, {
        method: 'DELETE',
      })

      if (res.ok) {
        setItems(items.filter(item => item.id !== id))
      } else {
        alert("Erro ao tentar apagar o item.")
      }
    } catch (error) {
      console.error(error)
      alert("Erro de conexão ao tentar apagar.")
    }
  }

  const urlToBase64 = async (url: string): Promise<string> => {
    const response = await fetch(url)
    const blob = await response.blob()
    return new Promise((resolve, reject) => {
      const reader = new FileReader()
      reader.onloadend = () => resolve(reader.result as string)
      reader.onerror = reject
      reader.readAsDataURL(blob)
    })
  }

  const handleGerarPDF = async () => {
    if (items.length === 0) return alert("Nenhum item cadastrado para gerar o relatório!")
    setPdfLoading(true)

    try {
      const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' })
      const dataHora = new Date().toLocaleString('pt-BR')

      // @ts-ignore
      // 🚀 COLOQUE O CÓDIGO DA SUA LOGO ENTRE AS ASPAS ABAIXO:
      const logoBase64Data = 'data:image/png;base64,'; 
      
      if (logoBase64Data) {
        try {
          doc.addImage(logoBase64Data, 'PNG', 14, 15, 12, 12) 
        } catch (e) {
          console.error("Erro ao desenho da logo:", e)
        }
      }

      // Títulos do Topo
      doc.setFont('Helvetica', 'bold')
      doc.setFontSize(18)
      doc.text('IBCC ONCOLOGIA', 30, 21) 
      
      doc.setFont('Helvetica', 'normal')
      doc.setFontSize(10)
      doc.text('Setor de Hotelaria', 30, 26) 

      // Cabeçalho Direita
      doc.setFont('Helvetica', 'normal')
      doc.setFontSize(9)
      doc.text(`Gerado em: ${dataHora}`, 196, 21, { align: 'right' })
      doc.text('Relatório: Inventário e Condenação de Entreposto', 196, 26, { align: 'right' })

      doc.setDrawColor(200, 200, 200)
      doc.line(14, 34, 196, 34)

      // Carregando dados e repassando o link original
      const tableRows = await Promise.all(
        items.map(async (item, index) => {
          let base64Image = ''
          try {
            const optimizedUrl = item.imageUrl.replace('/upload/', '/upload/w_100,h_100,c_fill/')
            base64Image = await urlToBase64(optimizedUrl)
          } catch (e) {
            console.error("Erro imagem item " + item.name, e)
          }

          return {
            num: index + 1,
            name: item.name,
            patrimony: item.patrimony ? item.patrimony : 'S/P',
            unit: item.unit || 'Não possui',
            status: item.status,
            imgData: base64Image,
            originalUrl: item.imageUrl // ✅ Link guardado para o clique do PDF
          }
        })
      )

      // Desenhando a tabela principal
      autoTable(doc, {
        startY: 40,
        head: [['Nº', 'Foto', 'Mobiliário / Descrição', 'Patrimônio', 'Unidade', 'Condição']],
        body: tableRows.map(row => [row.num, '', row.name, row.patrimony, row.unit, row.status]),
        styles: { valign: 'middle', fontSize: 9 },
        headStyles: { fillColor: '#4C80D2', textColor: '#ffffff', fontStyle: 'bold' },
        columnStyles: {
          0: { cellWidth: 8, halign: 'center' },
          1: { cellWidth: 22, halign: 'center' }, 
          2: { cellWidth: 62 },
          3: { cellWidth: 28, halign: 'center' },
          4: { cellWidth: 38, halign: 'center' },
          5: { cellWidth: 24, halign: 'center' }
        },
        didDrawCell: (data) => {
          if (data.section === 'body' && data.column.index === 1) {
            const rowIndex = data.row.index
            const base64Img = tableRows[rowIndex].imgData

            if (base64Img) {
              doc.addImage(base64Img, 'JPEG', data.cell.x + 2, data.cell.y + 2, 18, 18)
              
              // ✅ LINK INVISÍVEL NO PDF: Clicar na imagem abre o original grande na nuvem!
              doc.link(data.cell.x + 2, data.cell.y + 2, 18, 18, { url: tableRows[rowIndex].originalUrl })
            }
          }
        },
        bodyStyles: { minCellHeight: 22 }
      })

      // --- 4. BLOCO DE ASSINATURAS (NOVO) ---
      // @ts-ignore
      let finalY = doc.lastAutoTable.finalY + 25 // Dá um espaço confortável abaixo da tabela
      
      // Se passar de 240mm (borda limite), cria uma nova página para não quebrar o layout
      if (finalY > 240) { 
        doc.addPage()
        finalY = 45
      }

      doc.setDrawColor(120, 120, 120)
      doc.setLineWidth(0.3)

      // Desenha as 3 linhas de assinatura horizontais bem distribuídas
      doc.line(15, finalY, 65, finalY)   // Esquerda
      doc.line(80, finalY, 130, finalY)  // Meio
      doc.line(145, finalY, 195, finalY) // Direita

      // Cargos centralizados abaixo de suas respectivas linhas
      doc.setFont('Helvetica', 'bold')
      doc.setFontSize(9)
      doc.text('Hotelaria', 40, finalY + 5, { align: 'center' })
      doc.text('Gerência de Operações', 105, finalY + 5, { align: 'center' })
      doc.text('Gerente Geral', 170, finalY + 5, { align: 'center' })

      // Realiza o download do arquivo
      doc.save(`Inventario_Galpao_IBCC_${new Date().toISOString().slice(0,10)}.pdf`)

    } catch (error) {
      console.error(error)
      alert("Erro ao estruturar o PDF.")
    } finally {
      setPdfLoading(false)
    }
  }

  return (
    <div className="max-w-5xl mx-auto p-4 md:p-6">
      
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
        <div>
          <Link href="/admin/inventario" className="text-sm text-blue-600 hover:underline flex items-center gap-1 mb-2">
            <ArrowLeft className="w-4 h-4" /> Voltar para a Câmera
          </Link>
          <h1 className="text-2xl font-bold text-gray-800">Itens Mapeados no Galpão</h1>
          <p className="text-sm text-gray-500">Gerencie os registros e exporte o documento para PDF.</p>
        </div>

        <div className="flex gap-2">
          <button onClick={fetchItems} className="p-3 bg-gray-100 hover:bg-gray-200 rounded-xl text-gray-600">
            <RefreshCw className="w-5 h-5" />
          </button>
          
          <button onClick={handleGerarPDF} disabled={pdfLoading || loading} className="flex items-center justify-center gap-2 bg-red-600 hover:bg-red-700 text-white font-bold px-6 py-3 rounded-xl shadow-md disabled:opacity-50">
            {pdfLoading ? <><Loader2 className="w-5 h-5 animate-spin" />Processando...</> : <><FileText className="w-5 h-5" />Gerar PDF</>}
          </button>
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center p-12">
          <Loader2 className="w-8 h-8 animate-spin text-blue-600 mb-2" />
        </div>
      ) : items.length === 0 ? (
        <div className="text-center p-12 border-2 border-dashed border-gray-200 rounded-2xl bg-gray-50">
          <p className="text-gray-500 font-medium">Nenhum item catalogado ainda.</p>
        </div>
      ) : (
        <div className="bg-white border border-gray-200 rounded-2xl shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-gray-50 border-b border-gray-200 text-xs font-semibold text-gray-600 uppercase tracking-wider">
                  <th className="p-4 w-20 text-center">Foto</th>
                  <th className="p-4">Mobiliário</th>
                  <th className="p-4">Patrimônio</th>
                  <th className="p-4">Unidade</th>
                  <th className="p-4 text-center">Condição</th>
                  <th className="p-4 text-center">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100 text-sm">
                {items.map((item) => (
                  <tr key={item.id} className="hover:bg-gray-50/50">
                    <td className="p-4 flex justify-center">
                      {/* eslint-disable-next-line @next/next/no-img-element */}
                      <img 
                        src={item.imageUrl.replace('/upload/', '/upload/w_80,h_80,c_fill/')} 
                        alt={item.name} 
                        onClick={() => setZoomedImage(item.imageUrl)} 
                        className="w-12 h-12 rounded-lg object-cover border border-gray-200 cursor-pointer hover:opacity-75 transition-opacity shadow-sm" 
                        title="Clique para ampliar na tela"
                      />
                    </td>
                    <td className="p-4 font-medium text-gray-800">{item.name}</td>
                    <td className="p-4">
                      {item.patrimony ? <span className="bg-gray-100 px-2 py-1 rounded text-xs font-mono text-gray-600">{item.patrimony}</span> : <span className="text-gray-400 italic text-xs">S/P</span>}
                    </td>
                    <td className="p-4 text-gray-600">{item.unit || 'Não possui'}</td>
                    <td className="p-4 text-center">
                      <span className={`inline-block px-3 py-1 rounded-full text-xs font-bold ${
                        item.status === 'BOM' ? 'bg-green-100 text-green-700' :
                        item.status === 'CONSERTO' ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'
                      }`}>
                        {item.status}
                      </span>
                    </td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => handleDelete(item.id)}
                        className="p-2 text-red-500 hover:text-red-700 hover:bg-red-50 rounded-lg transition-colors"
                        title="Apagar registro"
                      >
                        <Trash2 className="w-5 h-5" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* MODAL DA IMAGEM AMPLIADA NA TELA PARA A HOTELARIA */}
      {zoomedImage && (
        <div 
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4 backdrop-blur-sm"
          onClick={() => setZoomedImage(null)}
        >
          <div className="relative max-w-4xl max-h-full flex flex-col items-center">
            <button 
              onClick={() => setZoomedImage(null)}
              className="absolute -top-12 right-0 text-white/70 hover:text-white p-2"
            >
              <X className="w-8 h-8" />
            </button>
            {/* eslint-disable-next-line @next/next/no-img-element */}
            <img 
              src={zoomedImage} 
              alt="Mobiliário Ampliado" 
              className="max-w-full max-h-[85vh] rounded-lg shadow-2xl object-contain border border-white/10"
              onClick={(e) => e.stopPropagation()} 
            />
          </div>
        </div>
      )}

    </div>
  )
}